/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements a pluggable transport layer for sending text messages.
 * The default transport logs sends; inject a real transport (Twilio,
 * AWS SNS, etc.) for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Transport function signature — abstracts the actual SMS delivery.
 * Return true for success, or throw/return false for failure.
 */
export type SmsTransport = (message: SmsMessage) => Promise<boolean>;

/**
 * A formatted SMS message ready for delivery.
 */
export interface SmsMessage {
  to: string;
  body: string;
}

/**
 * Configuration for the SmsAdapter.
 */
export interface SmsAdapterConfig {
  /** Optional custom transport. Defaults to logging transport. */
  transport?: SmsTransport;
}

const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

/**
 * Validate that a recipient string is a plausible E.164 phone number.
 */
export function isValidPhoneNumber(phone: string): boolean {
  return PHONE_REGEX.test(phone);
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private readonly transport: SmsTransport;
  /** Sent messages — accessible for testing. */
  readonly sentMessages: SmsMessage[] = [];

  constructor(config: SmsAdapterConfig = {}) {
    this.transport = config.transport ?? this.defaultTransport.bind(this);
  }

  /**
   * Format a notification payload into an SMS message.
   * SMS messages are plain text: subject + body, truncated if needed.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    return {
      to: payload.recipient,
      body: `${payload.subject}: ${payload.body}`,
    };
  }

  /**
   * Send an SMS notification.
   *
   * 1. Validates the recipient phone number (E.164 format).
   * 2. Formats the payload as a plain text message.
   * 3. Delivers via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidPhoneNumber(payload.recipient)) {
      this.logger.warn(`Invalid phone number: ${payload.recipient}`);
      return { success: false, error: `Invalid phone number: ${payload.recipient}` };
    }

    const message = this.formatMessage(payload);

    try {
      const delivered = await this.transport(message);
      if (delivered) {
        this.sentMessages.push(message);
        this.logger.info(`SMS sent to ${payload.recipient}: ${payload.subject}`);
        return { success: true };
      }
      this.logger.error(`Transport returned failure for ${payload.recipient}`);
      return { success: false, error: 'SMS delivery failed' };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Transport error for ${payload.recipient}: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }
  }

  /**
   * Default transport — logs the SMS and returns success.
   * Replaced with a real transport in production.
   */
  private async defaultTransport(message: SmsMessage): Promise<boolean> {
    this.logger.info(`[DefaultTransport] SMS -> ${message.to}: ${message.body}`);
    return true;
  }
}

