import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter, isValidPhoneNumber } from '../../src/adapters/sms.adapter.js';
import type { SmsTransport, SmsMessage } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'sms',
    metadata: { userId: 'user-123' },
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let delivered: SmsMessage[];
  let transport: SmsTransport;

  beforeEach(() => {
    delivered = [];
    transport = async (message) => {
      delivered.push(message);
      return true;
    };
    adapter = new SmsAdapter({ transport });
  });

  describe('send', () => {
    it('should deliver SMS through the transport', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(delivered).toHaveLength(1);
      expect(delivered[0]?.to).toBe('+15551234567');
      expect(delivered[0]?.body).toContain('Order Confirmation');
      expect(delivered[0]?.body).toContain('Your order has been placed');
    });

    it('should track sent messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.sentMessages).toHaveLength(1);
      expect(adapter.sentMessages[0]?.to).toBe('+15551234567');
    });

    it('should return failure for invalid phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-phone' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(delivered).toHaveLength(0);
    });

    it('should return failure when transport returns false', async () => {
      const failTransport: SmsTransport = async () => false;
      const failAdapter = new SmsAdapter({ transport: failTransport });

      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS delivery failed');
    });

    it('should catch transport errors and return failure', async () => {
      const errorTransport: SmsTransport = async () => {
        throw new Error('Service unavailable');
      };
      const errorAdapter = new SmsAdapter({ transport: errorTransport });

      const result = await errorAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Service unavailable');
    });
  });

  describe('formatMessage', () => {
    it('should format payload as subject: body', () => {
      const message = adapter.formatMessage(makePayload());

      expect(message.to).toBe('+15551234567');
      expect(message.body).toBe('Order Confirmation: order-1: Your order has been placed. Items: Widget x2. Total: $20.00');
    });

    it('should format all notification types', () => {
      const types = ['order_confirmation', 'order_status_update', 'welcome', 'account_update'] as const;
      for (const type of types) {
        const message = adapter.formatMessage(makePayload({ type, subject: `Test ${type}` }));
        expect(message.body).toContain(`Test ${type}`);
      }
    });
  });

  describe('isValidPhoneNumber', () => {
    it('should accept valid E.164 phone numbers', () => {
      expect(isValidPhoneNumber('+15551234567')).toBe(true);
      expect(isValidPhoneNumber('+442071234567')).toBe(true);
      expect(isValidPhoneNumber('+8613812345678')).toBe(true);
    });

    it('should reject invalid phone numbers', () => {
      expect(isValidPhoneNumber('')).toBe(false);
      expect(isValidPhoneNumber('5551234567')).toBe(false);
      expect(isValidPhoneNumber('+0123456789')).toBe(false);
      expect(isValidPhoneNumber('+1')).toBe(false);
      expect(isValidPhoneNumber('not-a-phone')).toBe(false);
      expect(isValidPhoneNumber('+1 555 123 4567')).toBe(false);
    });
  });

  describe('default transport', () => {
    it('should use default logging transport when none provided', async () => {
      const defaultAdapter = new SmsAdapter();
      const result = await defaultAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(defaultAdapter.sentMessages).toHaveLength(1);
    });
  });

  describe('channel property', () => {
    it('should expose sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });
});
